esqlQuery.esql:
FROM metrics-traefik.otel-*
// Limit to open connections gauge (per entrypoint, protocol)
| WHERE traefik_open_connections IS NOT NULL
// Take latest value per entrypoint/protocol (gauge - last value in window)
| STATS conns = MAX(traefik_open_connections) BY attributes.entrypoint, attributes.protocol
// Sum across entrypoints for total, or alert per entrypoint
| STATS total_conns = SUM(conns)
// Alert when connections exceed threshold; tune based on expected capacity
| WHERE total_conns > 1000
